#!/usr/bin/env python3
"""Generated by superpower-adapter.

Bounded 1-hop neighbor query over a wiki root's derived ``.graph.json``.

Usage:
  wiki_graph_neighbors.py --node "page.md#section" [--node ...] [--wiki-root project|shared] [--project-root PATH]
  wiki_graph_neighbors.py --node "page.md#section" --wiki-dir /path/to/wiki-repo
  wiki_graph_neighbors.py --nodes-stdin [--wiki-root ...]   # one node id per line

Returns ONLY the requested nodes' outgoing edges and incoming backlinks (with edge
type and an ``indexed`` flag indicating whether the neighbor page has a companion
``<stem>.index.md``). Output size scales with the number of requested nodes, never the
whole graph — this is the query that replaces reading the entire .graph.json into
context. A missing/unparseable graph degrades to empty neighbors plus a caveat; this is
a recall-improving convenience, never a hard failure.
"""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent))

from wiki_common import (  # noqa: E402
    one_hop_neighbors,
    repo_root,
    select_wiki_root,
    wiki_root_from_dir,
)

SECTION_GRAPH_FILE = ".graph.json"


def _configure_stdio() -> None:
    for stream in (sys.stdout, sys.stderr):
        if not hasattr(stream, "reconfigure"):
            continue
        try:
            stream.reconfigure(encoding="utf-8", errors="replace", newline="\n")
        except (OSError, ValueError):
            pass


def _load_graph(wiki_root: Path) -> tuple[dict | None, str | None]:
    """Return (graph_payload, caveat). Defensive: any failure degrades to (None, caveat)."""
    graph_path = wiki_root / SECTION_GRAPH_FILE
    if not graph_path.is_file():
        return None, f"{SECTION_GRAPH_FILE} not found at wiki root; no neighbors available"
    try:
        graph = json.loads(graph_path.read_text(encoding="utf-8"))
    except (OSError, ValueError) as exc:
        return None, f"could not parse {SECTION_GRAPH_FILE}: {exc}"
    if not isinstance(graph, dict):
        return None, f"{SECTION_GRAPH_FILE} is not a graph object"
    return graph, None


def _companion_index_rel(node: str) -> str | None:
    """Companion section-index rel path for a node's page, or None for a bare/odd node."""
    page = node.split("#", 1)[0]
    if not page.endswith(".md"):
        return None
    return page[: -len(".md")] + ".index.md"


def _annotate_indexed(wiki_root: Path, links: list[dict], page_key: str) -> list[dict]:
    """Add an ``indexed`` flag (companion <stem>.index.md exists) to each neighbor link."""
    annotated = []
    for link in links:
        node = link.get(page_key)
        companion = _companion_index_rel(node) if isinstance(node, str) else None
        indexed = bool(companion) and (wiki_root / companion).is_file()
        annotated.append({**link, "indexed": indexed})
    return annotated


def _gather_nodes(args: argparse.Namespace) -> list[str]:
    nodes: list[str] = list(args.node or [])
    if args.nodes_stdin:
        for raw in sys.stdin:
            line = raw.strip()
            if line:
                nodes.append(line)
    # Preserve order, drop duplicates.
    seen: set[str] = set()
    return [n for n in nodes if not (n in seen or seen.add(n))]


def main() -> None:
    _configure_stdio()
    parser = argparse.ArgumentParser(description="Query bounded 1-hop wiki graph neighbors.")
    parser.add_argument("--node", action="append", help="Node id 'page.md#section' (repeatable)")
    parser.add_argument("--nodes-stdin", action="store_true", help="Read additional node ids from stdin, one per line")
    parser.add_argument("--wiki-root", choices=["project", "shared"], default="project")
    parser.add_argument("--project-root", default=None, help="Project root (auto-detected if omitted)")
    parser.add_argument("--wiki-dir", default=None, help="Treat this directory as the wiki root directly (repo-root wiki layout)")
    args = parser.parse_args()

    nodes = _gather_nodes(args)
    if not nodes:
        parser.error("at least one --node (or --nodes-stdin input) is required")

    if args.wiki_dir:
        wiki = wiki_root_from_dir(args.wiki_dir)
    else:
        project = Path(args.project_root) if args.project_root else repo_root(Path.cwd())
        wiki = select_wiki_root(project, args.wiki_root)

    graph, caveat = _load_graph(wiki.path)
    slices = one_hop_neighbors(graph, nodes) if graph else {node: {"out": [], "in": []} for node in nodes}

    neighbors = {
        node: {
            "out": _annotate_indexed(wiki.path, slice_.get("out", []), "to"),
            "in": _annotate_indexed(wiki.path, slice_.get("in", []), "from"),
        }
        for node, slice_ in slices.items()
    }

    payload: dict[str, object] = {"neighbors": neighbors}
    if caveat:
        payload["caveats"] = [caveat]
    print(json.dumps(payload, indent=2, ensure_ascii=False))


if __name__ == "__main__":
    main()
